import React, { useState, useEffect, useRef, useMemo } from 'react';
import { X, Play, Pause, RotateCcw, Bell, Clock, SkipForward, Save, BookOpen, Check, Plus, FolderOpen, AlertCircle, Coffee, Repeat, Timer as TimerIcon, Settings, ChevronRight } from 'lucide-react';
import { TimerConfig, DeveloperStep, DevRecipe } from '../types';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { useLanguage } from '../contexts/LanguageContext';
import { storageService } from '../services/storageService';

// --- Types & Constants ---

const COLORS = {
    prewet: '#60A5FA', // Blue-400
    develop: '#F59E0B', // Amber-500
    stop: '#A855F7', // Purple-500
    fix: '#14B8A6', // Teal-500
    wash: '#06B6D4', // Cyan-500
};

const DEFAULT_CONFIG: TimerConfig = {
  processName: '',
  filmModel: '',
  devMethod: 'Hand',
  devLoopCount: 1,

  // Global Agitation Defaults
  globalAgitationEnabled: false,
  globalInitialAgitation: 30,
  globalAgitationDuration: 5,
  globalStandDuration: 55,

  enablePreWet: false,
  preWetName: 'Solution A',
  preWetDilution: '1:19',
  preWetVolume: '500',
  preWetTime: 60,

  developerSteps: [
    { 
      id: '1', 
      name: 'Solution A', 
      dilution: '1:19', 
      volume: '500', 
      duration: 390, 
      initialAgitation: 30, 
      agitationDuration: 5, 
      standDuration: 55,
      overrideGlobalAgitation: false 
    }
  ],

  enableStopBath: true,
  stopBathName: 'Solution A',
  stopBathDilution: '1:19',
  stopBathVolume: '500',
  stopTime: 60,

  fixerName: 'Solution A',
  fixerDilution: '1:4',
  fixerVolume: '500',
  fixTime: 300,
  fixInitialAgitation: 30,
  fixAgitationDuration: 5,
  fixStandDuration: 55,
  fixOverrideGlobalAgitation: false,

  washName: 'Water',
  washDilution: 'None',
  washVolume: '1000',
  washTime: 600,
  enableWettingAgent: false,
  wettingAgentName: 'Solution A',
  wettingAgentDilution: '1:200',
  wettingAgentVolume: '500'
};

const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
};

// --- Helper Components ---

const Timeline = ({ 
    phases, 
    currentIndex, 
    timeLeft, 
    totalTime 
}: { 
    phases: any[], 
    currentIndex: number, 
    timeLeft: number, 
    totalTime: number 
}) => {
    const { t } = useLanguage();

    // Calculate global position in seconds
    const elapsedPhasesTime = phases.slice(0, currentIndex).reduce((acc, p) => acc + p.duration, 0);
    const currentPhaseElapsed = phases[currentIndex] ? (phases[currentIndex].duration - timeLeft) : 0;
    const totalElapsed = elapsedPhasesTime + currentPhaseElapsed;
    const playheadPos = (totalElapsed / totalTime) * 100;

    return (
        <div className="w-full bg-gray-100 dark:bg-gray-800 p-4 border-b border-gray-200 dark:border-gray-700">
            <h4 className="text-[10px] uppercase font-bold text-gray-400 tracking-widest mb-3 flex justify-between">
                <span>{t('timer.timeline_overview')}</span>
                <span className="font-mono">{formatTime(totalElapsed)} / {formatTime(totalTime)}</span>
            </h4>
            <div className="relative h-12 bg-gray-200 dark:bg-gray-900 rounded-lg overflow-hidden flex shadow-inner">
                {phases.map((phase, idx) => {
                    const widthPercent = (phase.duration / totalTime) * 100;
                    const phaseColor = (COLORS as any)[phase.type] || '#CBD5E1';

                    return (
                        <div 
                            key={idx} 
                            className="relative h-full flex flex-col justify-end border-r border-black/10 last:border-0"
                            style={{ 
                                width: `${widthPercent}%`,
                                backgroundColor: phaseColor + '20' // 12.5% opacity
                            }}
                        >
                            {/* Agitation Stripes for Dev/Fix */}
                            {(phase.type === 'develop' || phase.type === 'fix') && (
                                <div className="absolute inset-0 pointer-events-none opacity-40">
                                    {/* Initial Agitation */}
                                    <div 
                                        className="absolute h-full top-0 left-0 bg-white/50 border-r border-black/5"
                                        style={{ width: `${(phase.initialAgitation / phase.duration) * 100}%` }}
                                    />
                                    {/* Cyclic Agitation */}
                                    {(() => {
                                        const stripes = [];
                                        const cycle = (phase.agitationDuration || 0) + (phase.standDuration || 0);
                                        if (cycle > 0) {
                                            for (let t = phase.initialAgitation; t < phase.duration; t += cycle) {
                                                const start = (t / phase.duration) * 100;
                                                const dur = (phase.agitationDuration / phase.duration) * 100;
                                                stripes.push(
                                                    <div 
                                                        key={t}
                                                        className="absolute h-full top-0 bg-white/40 border-r border-black/5"
                                                        style={{ left: `${start}%`, width: `${dur}%` }}
                                                    />
                                                );
                                            }
                                        }
                                        return stripes;
                                    })()}
                                </div>
                            )}

                            {/* Color bar at bottom */}
                            <div className="h-1.5 w-full" style={{ backgroundColor: phaseColor }}></div>

                            {/* Marker if current */}
                            {idx === currentIndex && (
                                <div className="absolute inset-0 bg-white/10 animate-pulse" />
                            )}
                        </div>
                    );
                })}

                {/* Playhead */}
                <div 
                    className="absolute top-0 bottom-0 w-0.5 bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.8)] z-20 transition-all duration-1000 linear"
                    style={{ left: `${playheadPos}%` }}
                >
                    <div className="absolute -top-1 -left-1 w-2.5 h-2.5 bg-red-500 rounded-full border border-white" />
                </div>
            </div>

            {/* Legend / Timeline Labels */}
            <div className="mt-3 flex gap-4 overflow-x-auto pb-1 no-scrollbar">
                {Object.entries(COLORS).map(([type, color]) => (
                    <div key={type} className="flex items-center gap-1.5 shrink-0">
                        <div className="w-2.5 h-2.5 rounded-sm" style={{ backgroundColor: color }}></div>
                        <span className="text-[10px] font-bold text-gray-500 uppercase">{t(`timer.phase_${type}`)}</span>
                    </div>
                ))}
            </div>
        </div>
    );
};

const TimeControl = ({ 
  label, 
  value, 
  onChange, 
  max = 1800,
  step = 5,
  disabled = false
}: { 
  label: string; 
  value: number; 
  onChange: (val: number) => void;
  max?: number;
  step?: number;
  disabled?: boolean;
}) => {
  const percentage = Math.min(100, (value / max) * 100);

  return (
    <div className={`w-full group relative transition-all duration-200 p-3 rounded-lg ${disabled ? 'opacity-50 pointer-events-none' : 'hover:bg-gray-50 dark:hover:bg-gray-800/50 focus-within:bg-indigo-50 dark:focus-within:bg-indigo-900/10 focus-within:ring-1 focus-within:ring-indigo-200 dark:focus-within:ring-indigo-800'}`}>
      <div className="flex justify-between items-center mb-2">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 group-focus-within:text-indigo-600 dark:group-focus-within:text-indigo-400 transition-colors">
            {label}
        </label>
        <div className="font-mono text-sm font-bold text-indigo-600 dark:text-indigo-400 bg-white dark:bg-gray-900 px-2 py-0.5 rounded border border-gray-200 dark:border-gray-700 shadow-sm min-w-[3.5rem] text-center">
            {formatTime(value)}
        </div>
      </div>

      <div className="relative h-6 flex items-center">
        <div className="absolute w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
             <div 
                className="h-full bg-indigo-500 dark:bg-indigo-400 transition-all duration-75"
                style={{ width: `${percentage}%` }}
             />
        </div>
        <input 
          type="range" 
          min="0" 
          max={max} 
          step={step} 
          value={Math.min(value, max)} 
          onChange={(e) => onChange(Number(e.target.value))}
          disabled={disabled}
          className="absolute w-full h-full opacity-0 cursor-pointer z-10"
        />
        <div 
            className="absolute h-4 w-4 bg-white border-2 border-indigo-600 rounded-full shadow pointer-events-none transition-all duration-75 group-focus-within:scale-125 group-focus-within:border-indigo-500"
            style={{ left: `calc(${percentage}% - 8px)` }}
        />
      </div>
    </div>
  );
};

const ChemicalInputs = ({
    nameLabel, nameValue, onNameChange,
    dilutionValue, onDilutionChange,
    volumeValue, onVolumeChange
}: {
    nameLabel: string;
    nameValue: string; onNameChange: (v: string) => void;
    dilutionValue: string; onDilutionChange: (v: string) => void;
    volumeValue: string; onVolumeChange: (v: string) => void;
}) => {
    const { t } = useLanguage();
    return (
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-3">
            <Input label={nameLabel} value={nameValue} onChange={e => onNameChange(e.target.value)} placeholder={t('placeholder.developerModel')} />
            <Input label={t('timer.stage_dilution')} value={dilutionValue} onChange={e => onDilutionChange(e.target.value)} placeholder="1:19" />
            <Input label={t('timer.volume_ml')} value={volumeValue} onChange={e => onVolumeChange(e.target.value)} placeholder="500" />
        </div>
    );
};

// --- Main Component ---

interface DevTimerProps {
  isOpen: boolean;
  onClose: () => void;
}

export const DevTimer: React.FC<DevTimerProps> = ({ isOpen, onClose }) => {
  const { t } = useLanguage();

  // --- State: UI Mode ---
  const [mode, setMode] = useState<'setup' | 'running' | 'finished'>('setup');

  // --- State: Configuration ---
  const [config, setConfig] = useState<TimerConfig>(DEFAULT_CONFIG);
  const [recipes, setRecipes] = useState<DevRecipe[]>([]);
  const [showRecipeSelect, setShowRecipeSelect] = useState(false);

  // --- State: Running Logic ---
  const [phases, setPhases] = useState<any[]>([]); 
  const [currentPhaseIndex, setCurrentPhaseIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isPaused, setIsPaused] = useState(true);
  const [agitationState, setAgitationState] = useState<'none' | 'agitate' | 'stand' | 'pre-warn'>('none');

  // Audio Context
  const audioCtxRef = useRef<AudioContext | null>(null);

  // --- Effects ---

  useEffect(() => {
    if (isOpen) {
      storageService.getRecipes().then(setRecipes);
    }
  }, [isOpen]);

  // Calculate Total Time
  const totalProcessTime = useMemo(() => {
    let total = 0;
    if (config.enablePreWet) total += config.preWetTime;

    // Developer
    const singleLoopDevTime = config.developerSteps.reduce((acc, step) => acc + step.duration, 0);
    total += singleLoopDevTime * Math.max(1, config.devLoopCount);

    if (config.enableStopBath) total += config.stopTime;
    total += config.fixTime;
    total += config.washTime;
    return total;
  }, [config]);

  // Build Phases
  useEffect(() => {
    const buildPhases = () => {
      const list: any[] = [];

      const getAgitationSettings = (local: {initial: number, agitate: number, stand: number}, override: boolean | undefined) => {
         if (config.globalAgitationEnabled && !override) {
             return {
                 initial: config.globalInitialAgitation ?? 30,
                 duration: config.globalAgitationDuration ?? 5,
                 stand: config.globalStandDuration ?? 55
             };
         }
         return {
             initial: local.initial,
             duration: local.agitate,
             stand: local.stand
         };
      };

      if (config.enablePreWet) {
        list.push({ 
            type: 'prewet', 
            label: config.preWetName || t('timer.phase_prewet'), 
            duration: config.preWetTime 
        });
      }

      const loops = Math.max(1, config.devLoopCount);
      for(let i=0; i<loops; i++) {
        config.developerSteps.forEach((step, idx) => {
          let name = step.name || t('timer.phase_develop');
          if (loops > 1) name += ` (${i+1}/${loops})`;

          const agi = getAgitationSettings(
              { initial: step.initialAgitation, agitate: step.agitationDuration, stand: step.standDuration },
              step.overrideGlobalAgitation
          );

          list.push({ 
            type: 'develop', 
            label: name, 
            duration: step.duration,
            initialAgitation: agi.initial,
            agitationDuration: agi.duration,
            standDuration: agi.stand
          });
        });
      }

      if (config.enableStopBath) {
        list.push({ 
            type: 'stop', 
            label: config.stopBathName || t('timer.phase_stop'), 
            duration: config.stopTime 
        });
      }

      const fixAgi = getAgitationSettings(
          { initial: config.fixInitialAgitation, agitate: config.fixAgitationDuration, stand: config.fixStandDuration },
          config.fixOverrideGlobalAgitation
      );

      list.push({ 
          type: 'fix', 
          label: config.fixerName || t('timer.phase_fix'), 
          duration: config.fixTime,
          initialAgitation: fixAgi.initial,
          agitationDuration: fixAgi.duration,
          standDuration: fixAgi.stand
      });

      list.push({ 
          type: 'wash', 
          label: config.washName || t('timer.phase_wash'), 
          duration: config.washTime 
      });

      setPhases(list);
    };

    buildPhases();
  }, [config, t]);

  // Timer Tick
  useEffect(() => {
    let interval: any = null;
    if (mode === 'running' && !isPaused && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (mode === 'running' && !isPaused && timeLeft === 0) {
      handlePhaseComplete();
    }
    return () => { if (interval) clearInterval(interval); };
  }, [mode, isPaused, timeLeft]);

  // Agitation Logic
  useEffect(() => {
    if (mode !== 'running' || isPaused) {
        setAgitationState('none');
        return;
    }

    const currentPhase = phases[currentPhaseIndex];
    if (!currentPhase || (currentPhase.type !== 'develop' && currentPhase.type !== 'fix')) {
        setAgitationState('none');
        return;
    }

    const initial = currentPhase.initialAgitation || 0;
    const agitateTime = currentPhase.agitationDuration || 0;
    const standTime = currentPhase.standDuration || 0;
    const cycleTime = agitateTime + standTime;
    const elapsed = currentPhase.duration - timeLeft;

    let newState: 'none' | 'agitate' | 'stand' | 'pre-warn' = 'stand';

    if (elapsed < initial) {
        newState = 'agitate';
    } 
    else if (cycleTime > 0) {
        const timeSinceInitial = elapsed - initial;
        const timeInCycle = timeSinceInitial % cycleTime;
        if (timeInCycle < agitateTime) {
             newState = 'agitate';
        } else {
             const timeUntilNextAgitate = cycleTime - timeInCycle;
             if (timeUntilNextAgitate <= 10 && timeUntilNextAgitate > 0 && timeLeft > 10) {
                 newState = 'pre-warn';
             } else {
                 newState = 'stand';
             }
        }
    } else {
        newState = 'stand';
    }

    if (newState !== agitationState) {
        if (newState === 'agitate') playStartChime(); 
        if (newState === 'stand') playEndChime();
        if (newState === 'pre-warn') playWarn();
        setAgitationState(newState);
    }

  }, [timeLeft, mode, isPaused, phases, currentPhaseIndex]);


  // --- Handlers ---

  const initAudio = () => {
    if (!audioCtxRef.current) {
        audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioCtxRef.current.state === 'suspended') {
        audioCtxRef.current.resume();
    }
  };

  const playTone = (freq: number, startTime: number, duration: number, vol: number = 0.2, type: OscillatorType = 'sine') => {
      if (!audioCtxRef.current) return;
      const osc = audioCtxRef.current.createOscillator();
      const gain = audioCtxRef.current.createGain();
      osc.type = type;
      osc.connect(gain);
      gain.connect(audioCtxRef.current.destination);
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(vol, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
      osc.start(startTime);
      osc.stop(startTime + duration);
  };

  const playStartChime = () => {
       if (!audioCtxRef.current) return;
       const now = audioCtxRef.current.currentTime;
       playTone(523.25, now, 0.4, 0.2, 'sine'); 
       playTone(659.25, now + 0.2, 0.6, 0.2, 'sine'); 
  };

  const playEndChime = () => {
       if (!audioCtxRef.current) return;
       const now = audioCtxRef.current.currentTime;
       playTone(659.25, now, 0.4, 0.2, 'sine'); 
       playTone(523.25, now + 0.2, 0.6, 0.2, 'sine'); 
  };

  const playWarn = () => {
       if (!audioCtxRef.current) return;
       const now = audioCtxRef.current.currentTime;
       playTone(392.00, now, 0.2, 0.15, 'sine'); 
       playTone(392.00, now + 0.25, 0.2, 0.15, 'sine');
  };

  const playPhaseEnd = () => {
       if (!audioCtxRef.current) return;
       const now = audioCtxRef.current.currentTime;
       playTone(523.25, now, 0.4, 0.15, 'sine'); 
       playTone(659.25, now + 0.1, 0.4, 0.15, 'sine'); 
       playTone(783.99, now + 0.2, 0.8, 0.15, 'sine'); 
  };

  const startTimer = () => {
    initAudio();
    if (mode === 'setup' || mode === 'finished') {
        setMode('running');
        setCurrentPhaseIndex(0);
        setTimeLeft(phases[0]?.duration || 0);
    }
    setIsPaused(false);
  };

  const handlePhaseComplete = () => {
    playPhaseEnd();
    if (currentPhaseIndex < phases.length - 1) {
        const nextIdx = currentPhaseIndex + 1;
        setCurrentPhaseIndex(nextIdx);
        setTimeLeft(phases[nextIdx].duration);
    } else {
        setMode('finished');
        setIsPaused(true);
    }
  };

  const reset = () => {
    setMode('setup');
    setIsPaused(true);
    setCurrentPhaseIndex(0);
  };

  const handleSaveRecipe = async () => {
    if (!config.processName) {
        alert(t('library.notes_placeholder')); 
        return;
    }
    const newRecipe: DevRecipe = {
        id: Date.now().toString(),
        name: config.processName,
        createdAt: Date.now(),
        updatedAt: Date.now(),
        notes: '',
        config: config
    };
    await storageService.saveRecipe(newRecipe);
    setRecipes(await storageService.getRecipes());
    alert(t('timer.saved_success'));
  };

  const handleSelectRecipe = (recipeId: string) => {
      const r = recipes.find(x => x.id === recipeId);
      if (r) {
          setConfig(JSON.parse(JSON.stringify(r.config)));
          setShowRecipeSelect(false);
      }
  };

  const getTimerBgClass = () => {
      if (agitationState === 'agitate') return 'bg-red-600 text-white';
      if (agitationState === 'pre-warn') return 'bg-orange-500 text-white';
      return 'bg-white dark:bg-gray-900 text-gray-900 dark:text-white';
  };

  if (!isOpen) return null;

  const currentPhase = phases[currentPhaseIndex];
  const nextPhase = phases[currentPhaseIndex + 1];
  const progressPercent = currentPhase ? ((currentPhase.duration - timeLeft) / currentPhase.duration) * 100 : 0;
  const currentPhaseColor = currentPhase ? (COLORS as any)[currentPhase.type] || '#4F46E5' : '#4F46E5';

  return (
    <div className="fixed inset-0 z-50 bg-white dark:bg-gray-900 flex flex-col">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-gray-200 dark:border-gray-800">
        <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <Clock className="w-5 h-5" /> {t('timer.title')}
        </h2>
        <button onClick={onClose} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <X className="w-6 h-6" />
        </button>
      </div>

      {/* Global Timeline Overlay (Only shown in running/finished mode) */}
      {(mode === 'running' || mode === 'finished') && (
          <Timeline 
            phases={phases} 
            currentIndex={currentPhaseIndex} 
            timeLeft={timeLeft} 
            totalTime={totalProcessTime} 
          />
      )}

      <div className="flex-1 overflow-hidden flex flex-col md:flex-row">

          {/* Phase List / Sidebar */}
          <div className="hidden md:flex flex-col w-72 bg-gray-50 dark:bg-gray-900 border-r border-gray-200 dark:border-gray-800 h-full">
              <div className="p-6 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-800 shrink-0">
                  <div className="flex items-center gap-2 mb-1">
                      <TimerIcon className="w-4 h-4 text-indigo-600 dark:text-indigo-400" />
                      <span className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{t('timer.total_time')}</span>
                  </div>
                  <div className="text-3xl font-mono font-bold text-gray-900 dark:text-white tracking-tight">
                      {formatTime(totalProcessTime)}
                  </div>
              </div>

              <div className="flex-1 flex flex-col overflow-y-auto bg-gray-100 dark:bg-gray-950/50">
                  <h3 className="p-4 text-xs font-bold text-gray-500 uppercase bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 sticky top-0 z-10">
                      {t('timer.stages')}
                  </h3>

                  <div className="flex-1 flex flex-col w-full h-full min-h-0">
                      {phases.map((p, idx) => {
                          const isCurrent = idx === currentPhaseIndex && mode === 'running';
                          const isDone = idx < currentPhaseIndex;
                          const pColor = (COLORS as any)[p.type] || '#4F46E5';

                          return (
                              <div 
                                key={idx} 
                                className={`
                                    relative flex items-center gap-3 px-4 border-b border-gray-200/50 dark:border-gray-800/50 transition-colors
                                    ${isCurrent ? 'bg-indigo-600 text-white z-10 shadow-md' : isDone ? 'bg-gray-200/50 dark:bg-gray-900/50 text-gray-400' : 'bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300'}
                                `}
                                style={{ 
                                    flexGrow: Math.max(1, p.duration), 
                                    minHeight: '4rem',
                                    flexBasis: '4rem'
                                }}
                              >
                                  <div className={`
                                      w-6 h-6 rounded-full flex items-center justify-center border text-xs font-mono shrink-0
                                      ${isCurrent ? 'border-white text-white' : isDone ? 'border-gray-400 text-gray-400' : 'border-gray-300 dark:border-gray-600'}
                                  `}>
                                      {isDone ? <Check className="w-3.5 h-3.5" /> : idx + 1}
                                  </div>
                                  <div className="min-w-0 flex-1">
                                      <div className="font-medium text-sm truncate">{p.label}</div>
                                      <div className="text-xs font-mono opacity-80">{formatTime(p.duration)}</div>
                                  </div>
                                  <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: pColor }}></div>
                              </div>
                          );
                      })}
                  </div>
              </div>
          </div>

          {/* Center Panel */}
          <div className="flex-1 flex flex-col relative">
              {mode === 'setup' ? (
                  <div className="flex-1 overflow-y-auto p-6 max-w-2xl mx-auto w-full">

                      <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-lg border border-gray-100 dark:border-gray-700 mb-6">
                        <h4 className="font-bold mb-3 flex items-center gap-2 text-gray-900 dark:text-white">
                             <BookOpen className="w-4 h-4"/> {t('timer.section_recipe')}
                        </h4>
                        <div className="flex flex-col sm:flex-row gap-2 items-end">
                             <div className="flex-1 w-full">
                                <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{t('timer.process_name')}</label>
                                <input 
                                    className="w-full rounded-md border-gray-300 dark:border-gray-600 shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white sm:text-sm focus:ring-2 focus:ring-indigo-500"
                                    value={config.processName} 
                                    onChange={e => setConfig({...config, processName: e.target.value})} 
                                    placeholder={t('placeholder.process_name')}
                                />
                             </div>
                             <div className="flex gap-2 w-full sm:w-auto">
                                <Button variant="secondary" onClick={() => setShowRecipeSelect(true)} className="flex-1 sm:flex-none">
                                    <FolderOpen className="w-4 h-4 mr-1"/> {t('timer.select_short')}
                                </Button>
                                <Button variant="primary" onClick={handleSaveRecipe} className="flex-1 sm:flex-none">
                                    <Save className="w-4 h-4 mr-1"/> {t('timer.save_short')}
                                </Button>
                             </div>
                        </div>
                      </div>

                      {showRecipeSelect && (
                          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
                              <div className="bg-white dark:bg-gray-800 rounded-xl shadow-xl w-full max-w-md max-h-[80vh] flex flex-col">
                                  <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center">
                                      <h3 className="font-bold text-lg">{t('timer.select_modal_title')}</h3>
                                      <button onClick={() => setShowRecipeSelect(false)}><X className="w-5 h-5"/></button>
                                  </div>
                                  <div className="flex-1 overflow-y-auto p-2">
                                      {recipes.length === 0 && <p className="text-center p-4 text-gray-500">{t('library.empty')}</p>}
                                      {recipes.map(r => (
                                          <button 
                                            key={r.id} 
                                            onClick={() => handleSelectRecipe(r.id)}
                                            className="w-full text-left p-3 hover:bg-gray-50 dark:hover:bg-gray-700 rounded-lg transition-colors border-b border-gray-50 dark:border-gray-700 last:border-0"
                                          >
                                              <div className="font-medium">{r.name}</div>
                                              <div className="text-xs text-gray-500 flex gap-2 mt-1">
                                                  <span>{r.config.developerSteps[0]?.name}</span>
                                                  <span>•</span>
                                                  <span>{t(`enum.${r.config.devMethod}`)}</span>
                                              </div>
                                          </button>
                                      ))}
                                  </div>
                              </div>
                          </div>
                      )}

                      <div className="space-y-8">
                          {/* Global Settings */}
                          <div className="border-t pt-4 dark:border-gray-700">
                               <div className="flex items-center justify-between mb-4">
                                   <h4 className="font-bold text-gray-900 dark:text-white flex items-center gap-2">
                                       <Settings className="w-4 h-4" /> {t('timer.global_agitation')}
                                   </h4>
                                   <label className="flex items-center gap-2 cursor-pointer">
                                       <input 
                                         type="checkbox"
                                         className="w-4 h-4 text-indigo-600 rounded"
                                         checked={config.globalAgitationEnabled}
                                         onChange={e => setConfig({...config, globalAgitationEnabled: e.target.checked})}
                                       />
                                       <span className="text-sm font-medium">{t('timer.global_agitation_enable')}</span>
                                   </label>
                               </div>
                               {config.globalAgitationEnabled && (
                                   <div className="p-4 bg-indigo-50 dark:bg-indigo-900/10 rounded-lg border border-indigo-100 dark:border-indigo-800/30 grid grid-cols-2 gap-4">
                                        <div className="col-span-2">
                                            <TimeControl 
                                                label={t('timer.initial_agitation')} 
                                                value={config.globalInitialAgitation ?? 30} 
                                                max={300}
                                                onChange={val => setConfig({...config, globalInitialAgitation: val})} 
                                            />
                                        </div>
                                        <TimeControl 
                                            label={t('timer.agitation_duration')} 
                                            value={config.globalAgitationDuration ?? 5} 
                                            max={300}
                                            onChange={val => setConfig({...config, globalAgitationDuration: val})} 
                                        />
                                        <TimeControl 
                                            label={t('timer.stand_duration')} 
                                            value={config.globalStandDuration ?? 55} 
                                            max={300}
                                            onChange={val => setConfig({...config, globalStandDuration: val})} 
                                        />
                                   </div>
                               )}
                          </div>

                          {/* Pre-wet */}
                          <div className="border-t pt-4 dark:border-gray-700">
                              <label className="flex items-center gap-2 mb-4">
                                  <input 
                                    type="checkbox" 
                                    className="w-4 h-4 text-indigo-600 rounded"
                                    checked={config.enablePreWet} 
                                    onChange={e => setConfig({...config, enablePreWet: e.target.checked})} 
                                  />
                                  <span className="font-bold text-gray-900 dark:text-white">{t('timer.phase_prewet')}</span>
                              </label>
                              {config.enablePreWet && (
                                  <div className="pl-4 border-l-2 border-gray-200 dark:border-gray-700 ml-2">
                                      <ChemicalInputs 
                                        nameLabel={t('timer.agent_name')}
                                        nameValue={config.preWetName} onNameChange={v => setConfig({...config, preWetName: v})}
                                        dilutionValue={config.preWetDilution} onDilutionChange={v => setConfig({...config, preWetDilution: v})}
                                        volumeValue={config.preWetVolume} onVolumeChange={v => setConfig({...config, preWetVolume: v})}
                                      />
                                      <TimeControl 
                                        label={t('timer.duration_label')} 
                                        value={config.preWetTime} 
                                        max={300} 
                                        onChange={val => setConfig({...config, preWetTime: val})} 
                                      />
                                  </div>
                              )}
                          </div>

                          {/* Development */}
                          <div className="border-t pt-4 dark:border-gray-700">
                               <h4 className="font-bold mb-3 text-gray-900 dark:text-white">{t('timer.section_dev')}</h4>
                               {config.developerSteps.map((step, idx) => (
                                   <div key={step.id} className="mb-6 p-4 bg-gray-50 dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700 shadow-sm">
                                       <ChemicalInputs 
                                            nameLabel={t('timer.dev_liquid_name')}
                                            nameValue={step.name} onNameChange={v => {
                                                const newSteps = [...config.developerSteps];
                                                newSteps[idx].name = v;
                                                setConfig({...config, developerSteps: newSteps});
                                            }}
                                            dilutionValue={step.dilution} onDilutionChange={v => {
                                                const newSteps = [...config.developerSteps];
                                                newSteps[idx].dilution = v;
                                                setConfig({...config, developerSteps: newSteps});
                                            }}
                                            volumeValue={step.volume} onVolumeChange={v => {
                                                const newSteps = [...config.developerSteps];
                                                newSteps[idx].volume = v;
                                                setConfig({...config, developerSteps: newSteps});
                                            }}
                                       />
                                       <div className="space-y-4 pt-4 border-t border-gray-200 dark:border-gray-700 mt-2">
                                            <TimeControl 
                                                label={t('timer.duration_label')} 
                                                value={step.duration} 
                                                onChange={val => {
                                                    const newSteps = [...config.developerSteps];
                                                    newSteps[idx].duration = val;
                                                    setConfig({...config, developerSteps: newSteps});
                                                }} 
                                            />
                                       </div>
                                   </div>
                               ))}
                          </div>

                          {/* Fixer */}
                           <div className="border-t pt-4 dark:border-gray-700">
                               <h4 className="font-bold mb-3 text-gray-900 dark:text-white">{t('timer.section_fix')}</h4>
                               <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700 shadow-sm">
                                   <ChemicalInputs 
                                        nameLabel={t('timer.fix_liquid_name')}
                                        nameValue={config.fixerName} onNameChange={v => setConfig({...config, fixerName: v})}
                                        dilutionValue={config.fixerDilution} onDilutionChange={v => setConfig({...config, fixerDilution: v})}
                                        volumeValue={config.fixerVolume} onVolumeChange={v => setConfig({...config, fixerVolume: v})}
                                   />
                                   <TimeControl 
                                      label={t('timer.duration_label')} 
                                      value={config.fixTime} 
                                      max={1200} 
                                      onChange={val => setConfig({...config, fixTime: val})} 
                                   />
                               </div>
                           </div>

                           {/* Wash */}
                           <div className="border-t pt-4 dark:border-gray-700 pb-8">
                               <h4 className="font-bold mb-3 text-gray-900 dark:text-white">{t('timer.section_wash')}</h4>
                               <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700 shadow-sm">
                                   <ChemicalInputs 
                                        nameLabel={t('timer.agent_name')}
                                        nameValue={config.washName} onNameChange={v => setConfig({...config, washName: v})}
                                        dilutionValue={config.washDilution} onDilutionChange={v => setConfig({...config, washDilution: v})}
                                        volumeValue={config.washVolume} onVolumeChange={v => setConfig({...config, washVolume: v})}
                                   />
                                   <TimeControl 
                                      label={t('timer.duration_label')} 
                                      value={config.washTime} 
                                      onChange={val => setConfig({...config, washTime: val})} 
                                   />
                               </div>
                           </div>
                      </div>
                  </div>
              ) : mode === 'finished' ? (
                  <div className="flex-1 flex flex-col items-center justify-center p-8 text-center">
                      <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6">
                          <Check className="w-10 h-10" />
                      </div>
                      <h2 className="text-3xl font-bold mb-2 text-gray-900 dark:text-white">{t('timer.finished_msg')}</h2>
                      <Button size="lg" onClick={reset} className="mt-8">{t('timer.close')}</Button>
                  </div>
              ) : (
                  <div className={`flex-1 flex flex-col items-center justify-center p-8 transition-colors duration-500 ${getTimerBgClass()}`}>
                      <div className="text-center w-full max-w-md">
                          <div className={`text-sm font-bold uppercase tracking-widest mb-2 ${agitationState !== 'none' && agitationState !== 'stand' ? 'text-white/80' : 'text-gray-500'}`}>
                              {t('timer.step_progress', { current: currentPhaseIndex + 1, total: phases.length })}
                          </div>

                          <div className="flex flex-col items-center mb-8">
                             <h2 className={`text-4xl md:text-5xl font-bold ${agitationState !== 'none' && agitationState !== 'stand' ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                                 {currentPhase?.label}
                             </h2>
                             {nextPhase && (
                                 <div className={`mt-2 flex items-center gap-1 text-sm ${agitationState !== 'none' && agitationState !== 'stand' ? 'text-white/70' : 'text-gray-400 dark:text-gray-500'}`}>
                                     <span>{t('timer.next')}:</span>
                                     <span className="font-medium">{nextPhase.label}</span>
                                     <ChevronRight className="w-3 h-3" />
                                 </div>
                             )}
                          </div>

                          <div className={`text-9xl font-mono font-bold tracking-tighter mb-8 tabular-nums ${agitationState !== 'none' && agitationState !== 'stand' ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                              {formatTime(timeLeft)}
                          </div>

                          <div className="w-full h-8 bg-gray-200/50 dark:bg-gray-800/50 rounded-full overflow-hidden mb-8 backdrop-blur-sm border border-black/5 dark:border-white/10">
                              <div 
                                className={`h-full transition-all duration-1000 linear`} 
                                style={{ 
                                    width: `${progressPercent}%`, 
                                    backgroundColor: agitationState !== 'none' && agitationState !== 'stand' ? '#FFFFFF' : currentPhaseColor 
                                }}
                              />
                          </div>

                          <div className="h-16 flex items-center justify-center">
                             {agitationState === 'agitate' && (
                                 <div className="flex items-center gap-2 text-3xl font-bold animate-bounce text-white">
                                     <Bell className="w-8 h-8 fill-current" /> {t('timer.alert_agitate')}
                                 </div>
                             )}
                             {agitationState === 'pre-warn' && (
                                 <div className="flex items-center gap-2 text-2xl font-bold animate-pulse text-white">
                                     <AlertCircle className="w-8 h-8" /> {t('timer.alert_pre_agitate')}
                                 </div>
                             )}
                             {agitationState === 'stand' && (
                                 <div className="flex items-center gap-2 text-xl font-bold text-gray-400">
                                     <Coffee className="w-6 h-6" /> {t('timer.alert_stand')}
                                 </div>
                             )}
                          </div>
                      </div>
                  </div>
              )}

              <div className="p-4 border-t border-gray-200 dark:border-gray-800 bg-gray-50 dark:bg-gray-900">
                  <div className="max-w-md mx-auto flex justify-center gap-4">
                      {mode === 'setup' ? (
                          <Button size="lg" className="w-full" onClick={startTimer}>
                              <Play className="w-5 h-5 mr-2" /> {t('timer.start')}
                          </Button>
                      ) : mode === 'running' ? (
                          <>
                            <Button variant="secondary" onClick={reset}><RotateCcw className="w-5 h-5" /></Button>
                            <Button 
                                size="lg" 
                                className="w-32" 
                                onClick={() => setIsPaused(!isPaused)}
                            >
                                {isPaused ? <Play className="w-5 h-5" /> : <Pause className="w-5 h-5" />}
                            </Button>
                            <Button variant="secondary" onClick={handlePhaseComplete}><SkipForward className="w-5 h-5" /></Button>
                          </>
                      ) : null}
                  </div>
              </div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Camera, Beaker, Upload, Image as ImageIcon, BookOpen } from 'lucide-react';
import { FilmRecord, FilmFormat, DevMethod, FILM_FORMATS, DEV_METHODS, DevRecipe } from '../types';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { useLanguage } from '../contexts/LanguageContext';
import { storageService } from '../services/storageService';

interface RecordEditorProps {
  initialData?: FilmRecord | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: FilmRecord) => Promise<void>;
}

const emptyRecord: Omit<FilmRecord, 'id' | 'createdAt' | 'updatedAt'> = {
  date: Date.now(),
  filmModel: '',
  format: '135',
  aperture: '',
  shutterSpeed: '',
  flashPower: '',
  location: '',
  locationImage: null,
  shootingNotes: '',
  devMethod: 'Hand',
  devProcess: 'BW',
  developerModel: '',
  fixerModel: '',
  devDilution: '',
  fixDilution: '',
  isPreWet: false,
  devTime: '',
  fixTime: '',
  devNotes: '',
  filmImage: null,
};

// Helper to format timestamp for datetime-local input (YYYY-MM-DDThh:mm)
const formatDateForInput = (timestamp: number) => {
  const date = new Date(timestamp);
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

// Helper to format Seconds to M:SS
const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
};

export const RecordEditor: React.FC<RecordEditorProps> = ({ initialData, isOpen, onClose, onSave }) => {
  const { t } = useLanguage();
  const [activeTab, setActiveTab] = useState<'shooting' | 'developing'>('shooting');
  const [formData, setFormData] = useState<any>(emptyRecord);
  const [isSaving, setIsSaving] = useState(false);
  const [recipes, setRecipes] = useState<DevRecipe[]>([]);

  useEffect(() => {
    if (isOpen) {
      const initialDate = initialData 
        ? (initialData.date || initialData.createdAt || Date.now()) 
        : Date.now();

      setFormData({
        ...(initialData || emptyRecord),
        date: initialDate
      });
      setActiveTab('shooting');

      storageService.getRecipes().then(setRecipes);
    }
  }, [isOpen, initialData]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'locationImage' | 'filmImage') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData((prev: any) => ({ ...prev, [field]: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const dateString = e.target.value;
    if (dateString) {
      const timestamp = new Date(dateString).getTime();
      setFormData({ ...formData, date: timestamp });
    }
  };

  const handleRecipeSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const recipeId = e.target.value;
      if(!recipeId) return;
      const recipe = recipes.find(r => r.id === recipeId);
      if(recipe) {
          const totalDevSeconds = recipe.config.developerSteps.reduce((acc, step) => acc + step.duration, 0) * recipe.config.devLoopCount;

          setFormData({
              ...formData,
              devMethod: recipe.config.devMethod,
              developerModel: recipe.config.developerModel,
              devDilution: recipe.config.developerSteps[0]?.dilution || '',
              devTime: formatTime(totalDevSeconds),
              fixTime: formatTime(recipe.config.fixTime),
              isPreWet: recipe.config.enablePreWet,
              devNotes: recipe.notes || formData.devNotes
          });
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const recordToSave: FilmRecord = {
        ...formData,
        id: initialData?.id || Date.now().toString(),
        createdAt: initialData?.createdAt || Date.now(),
        updatedAt: Date.now(),
      };
      await onSave(recordToSave);
      onClose();
    } catch (error) {
      console.error("Failed to save", error);
      alert(t('editor.save_fail'));
    } finally {
      setIsSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex items-center justify-center min-h-screen px-4 pt-4 pb-20 text-center sm:block sm:p-0">
        <div className="fixed inset-0 transition-opacity bg-gray-500 bg-opacity-75" onClick={onClose} />

        <div className="inline-block w-full max-w-2xl my-8 overflow-hidden text-left align-middle transition-all transform bg-white dark:bg-gray-800 shadow-xl rounded-2xl">
          <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white">
              {initialData ? t('editor.edit_title') : t('editor.new_title')}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-500 dark:hover:text-gray-300">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex border-b border-gray-200 dark:border-gray-700">
            <button
              onClick={() => setActiveTab('shooting')}
              className={`flex-1 py-3 text-sm font-medium text-center border-b-2 transition-colors flex items-center justify-center gap-2 ${
                activeTab === 'shooting'
                  ? 'border-indigo-500 text-indigo-600 dark:text-indigo-400 bg-indigo-50/50 dark:bg-indigo-900/20'
                  : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'
              }`}
            >
              <Camera className="w-4 h-4" /> {t('editor.tab_shooting')}
            </button>
            <button
              onClick={() => setActiveTab('developing')}
              className={`flex-1 py-3 text-sm font-medium text-center border-b-2 transition-colors flex items-center justify-center gap-2 ${
                activeTab === 'developing'
                  ? 'border-indigo-500 text-indigo-600 dark:text-indigo-400 bg-indigo-50/50 dark:bg-indigo-900/20'
                  : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'
              }`}
            >
              <Beaker className="w-4 h-4" /> {t('editor.tab_developing')}
            </button>
          </div>

          <form onSubmit={handleSubmit} className="px-6 py-6 max-h-[70vh] overflow-y-auto">
            {activeTab === 'shooting' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <Input
                  label={t('field.date')}
                  type="datetime-local"
                  value={formatDateForInput(formData.date)}
                  onChange={handleDateChange}
                  required
                  className="md:col-span-2 font-mono"
                />

                <Input
                  label={t('field.filmModel')}
                  placeholder={t('placeholder.filmModel')}
                  value={formData.filmModel}
                  onChange={(e) => setFormData({ ...formData, filmModel: e.target.value })}
                  required
                  className="md:col-span-2"
                />

                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('field.format')}</label>
                  <select
                    className="w-full rounded-md border-gray-300 dark:border-gray-600 border shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm"
                    value={formData.format}
                    onChange={(e) => setFormData({ ...formData, format: e.target.value as FilmFormat })}
                  >
                    {FILM_FORMATS.map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                </div>

                <Input
                  label={t('field.location')}
                  placeholder={t('placeholder.location')}
                  value={formData.location}
                  onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                />

                <Input
                  label={t('field.aperture')}
                  placeholder={t('placeholder.aperture')}
                  value={formData.aperture}
                  onChange={(e) => setFormData({ ...formData, aperture: e.target.value })}
                />

                <Input
                  label={t('field.shutterSpeed')}
                  placeholder={t('placeholder.shutterSpeed')}
                  value={formData.shutterSpeed}
                  onChange={(e) => setFormData({ ...formData, shutterSpeed: e.target.value })}
                />

                <Input
                  label={t('field.flashPower')}
                  placeholder={t('placeholder.flashPower')}
                  value={formData.flashPower}
                  onChange={(e) => setFormData({ ...formData, flashPower: e.target.value })}
                />

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('editor.preview_location')}</label>
                  <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 dark:border-gray-600 border-dashed rounded-md hover:border-indigo-400 dark:hover:border-indigo-500 transition-colors">
                    <div className="space-y-1 text-center">
                      {formData.locationImage ? (
                        <div className="relative">
                            <img src={formData.locationImage} alt="Preview" className="mx-auto h-32 object-contain" />
                            <button 
                                type="button"
                                onClick={() => setFormData({...formData, locationImage: null})}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 hover:bg-red-600"
                            >
                                <X className="w-3 h-3" />
                            </button>
                        </div>
                      ) : (
                        <>
                          <ImageIcon className="mx-auto h-12 w-12 text-gray-400 dark:text-gray-500" />
                          <div className="flex text-sm text-gray-600 dark:text-gray-400 justify-center">
                            <label className="relative cursor-pointer bg-white dark:bg-gray-700 rounded-md font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-500 dark:hover:text-indigo-300 focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-indigo-500">
                              <span className="px-1">{t('editor.upload')}</span>
                              <input type="file" className="sr-only" accept="image/*" onChange={(e) => handleImageUpload(e, 'locationImage')} />
                            </label>
                          </div>
