const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
};

// --- Helper Components ---

const AnnotatedTimeline = ({ 
    phases, 
    currentIndex, 
    timeLeft, 
    totalTime 
}: { 
    phases: any[], 
    currentIndex: number, 
    timeLeft: number, 
    totalTime: number 
}) => {
    const { t } = useLanguage();

    // Calculate global position in seconds
    const elapsedPhasesTime = phases.slice(0, currentIndex).reduce((acc, p) => acc + p.duration, 0);
    const currentPhaseElapsed = phases[currentIndex] ? (phases[currentIndex].duration - timeLeft) : 0;
    const totalElapsed = elapsedPhasesTime + currentPhaseElapsed;
    const playheadPos = (totalElapsed / totalTime) * 100;

    return (
        <div className="w-full bg-white dark:bg-gray-950 p-6 border-b border-gray-200 dark:border-gray-800">
            <h4 className="text-[10px] uppercase font-bold text-gray-400 tracking-widest mb-4 flex justify-between">
                <span>{t('timer.timeline_overview')}</span>
                <span className="font-mono text-gray-500">{formatTime(totalElapsed)} / {formatTime(totalTime)}</span>
            </h4>

            <div className="relative flex flex-col gap-6">
                {/* The Bold Bar Container */}
                <div className="relative h-14 bg-gray-100 dark:bg-gray-900 rounded-full overflow-hidden flex shadow-inner border border-gray-200 dark:border-gray-800">
                    {phases.map((phase, idx) => {
                        const widthPercent = (phase.duration / totalTime) * 100;
                        const phaseColor = (COLORS as any)[phase.type] || '#CBD5E1';

                        return (
                            <div 
                                key={idx} 
                                className="relative h-full flex flex-col justify-end transition-all duration-300"
                                style={{ 
                                    width: `${widthPercent}%`,
                                    backgroundColor: phaseColor + (idx === currentIndex ? 'FF' : '33') // Full opacity for current, 20% for others
                                }}
                            >
                                {idx === currentIndex && (
                                    <div className="absolute inset-0 bg-white/10 animate-pulse" />
                                )}
                            </div>
                        );
                    })}

                    {/* Playhead */}
                    <div 
                        className="absolute top-0 bottom-0 w-1 bg-white shadow-[0_0_15px_rgba(255,255,255,0.8)] z-20 transition-all duration-1000 linear"
                        style={{ left: `${playheadPos}%` }}
                    />
                </div>

                {/* Annotation Area (Current Phase) */}
                <div className="relative flex items-center justify-center h-20">
                     <div className="flex items-center w-full max-w-lg">
                        {/* Bar Segment Representative */}
                        <div 
                            className="w-16 h-12 rounded-lg flex items-center justify-center shrink-0 shadow-lg border-2 border-white dark:border-gray-800"
                            style={{ backgroundColor: (COLORS as any)[phases[currentIndex]?.type] || '#4F46E5' }}
                        >
                            <TimerIcon className="w-6 h-6 text-white" />
                        </div>

                        {/* Dashed Indicator */}
                        <div className="flex-1 h-px border-b-2 border-dashed border-gray-300 dark:border-gray-700 mx-4" />

                        {/* Text Label & Time */}
                        <div className="text-right shrink-0">
                            <div className="text-sm font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-1">
                                {phases[currentIndex]?.label}
                            </div>
                            <div className="text-2xl font-mono font-bold text-gray-900 dark:text-white tabular-nums">
                                {formatTime(phases[currentIndex]?.duration)}
                            </div>
                        </div>
                     </div>
                </div>
            </div>
        </div>
    );
};

