                                       <ChemicalInputs 
                                            nameLabel={t('timer.dev_liquid_name')}
                                            nameValue={step.name} onNameChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].name = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            dilutionValue={step.dilution} onDilutionChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].dilution = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            volumeValue={step.volume} onVolumeChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].volume = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                       />
                                       <TimeControl label={t('timer.duration_label')} value={step.duration} onChange={val => {
                                            const newSteps = [...config.developerSteps]; newSteps[idx].duration = val; setConfig({...config, developerSteps: newSteps});
