                                  </div>
                                  <input 
                                    type="checkbox" 
                                    className="w-5 h-5 text-purple-600 rounded-md focus:ring-purple-500"
                                    checked={config.enableStopBath} 
                                    onChange={e => setConfig({...config, enableStopBath: e.target.checked})} 
                                  />
                              </label>
                              {config.enableStopBath && (
                                  <div className="p-4 bg-purple-50 dark:bg-purple-900/10 rounded-xl border border-purple-100 dark:border-purple-800/30">
                                      <ChemicalInputs 
                                        nameLabel={t('timer.stop_agent')}
                                        nameValue={config.stopBathName} onNameChange={v => setConfig({...config, stopBathName: v})}
                                        dilutionValue={config.stopBathDilution} onDilutionChange={v => setConfig({...config, stopBathDilution: v})}
                                        volumeValue={config.stopBathVolume} onVolumeChange={v => setConfig({...config, stopBathVolume: v})}
                                      />
                                      <TimeControl label={t('timer.duration_label')} value={config.stopTime} max={300} onChange={val => setConfig({...config, stopTime: val})} />
                                  </div>
                              )}
                          </div>

                          <div className="border-t pt-4 dark:border-gray-700">
                               <h4 className="font-bold mb-4 text-gray-900 dark:text-white flex items-center gap-2">
                                  <span className="w-2 h-2 rounded-full bg-teal-500"></span>
                                  {t('timer.section_fix')}
                               </h4>
                               <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                                   <ChemicalInputs 
                                        nameLabel={t('timer.fix_liquid_name')}
                                        nameValue={config.fixerName} onNameChange={v => setConfig({...config, fixerName: v})}
                                        dilutionValue={config.fixerDilution} onDilutionChange={v => setConfig({...config, fixerDilution: v})}
                                        volumeValue={config.fixerVolume} onVolumeChange={v => setConfig({...config, fixerVolume: v})}
                                   />
                                   <TimeControl label={t('timer.duration_label')} value={config.fixTime} max={1200} onChange={val => setConfig({...config, fixTime: val})} />
                               </div>
                          </div>

                           <div className="border-t pt-4 dark:border-gray-700 pb-8">
                               <h4 className="font-bold mb-4 text-gray-900 dark:text-white flex items-center gap-2">
                                  <span className="w-2 h-2 rounded-full bg-cyan-500"></span>
                                  {t('timer.section_wash')}
                               </h4>
                               <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                                   <ChemicalInputs 
                                        nameLabel={t('timer.agent_name')}
                                        nameValue={config.washName} onNameChange={v => setConfig({...config, washName: v})}
                                        dilutionValue={config.washDilution} onDilutionChange={v => setConfig({...config, washDilution: v})}
                                        volumeValue={config.washVolume} onVolumeChange={v => setConfig({...config, washVolume: v})}
                                   />
                                   <TimeControl label={t('timer.duration_label')} value={config.washTime} onChange={val => setConfig({...config, washTime: val})} />
