const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
};

// --- Helper Components ---

const AnnotatedTimeline = ({ 
    phases, 
    currentIndex, 
    timeLeft, 
    totalTime 
}: { 
    phases: any[], 
    currentIndex: number, 
    timeLeft: number, 
    totalTime: number 
}) => {
    const { t } = useLanguage();

    // Calculate global position in seconds
    const elapsedPhasesTime = phases.slice(0, currentIndex).reduce((acc, p) => acc + p.duration, 0);
    const currentPhaseElapsed = phases[currentIndex] ? (phases[currentIndex].duration - timeLeft) : 0;
    const totalElapsed = elapsedPhasesTime + currentPhaseElapsed;
    const playheadPos = (totalElapsed / totalTime) * 100;

    return (
        <div className="w-full bg-white dark:bg-gray-950 p-6 border-b border-gray-200 dark:border-gray-800">
            <h4 className="text-[10px] uppercase font-bold text-gray-400 tracking-widest mb-4 flex justify-between">
                <span>{t('timer.timeline_overview')}</span>
                <span className="font-mono text-gray-500">{formatTime(totalElapsed)} / {formatTime(totalTime)}</span>
            </h4>

            <div className="relative flex flex-col gap-6">
                {/* The Bold Bar Container */}
                <div className="relative h-14 bg-gray-100 dark:bg-gray-900 rounded-full overflow-hidden flex shadow-inner border border-gray-200 dark:border-gray-800">
                    {phases.map((phase, idx) => {
                        const widthPercent = (phase.duration / totalTime) * 100;
                        const phaseColor = (COLORS as any)[phase.type] || '#CBD5E1';

                        return (
                            <div 
                                key={idx} 
                                className="relative h-full flex flex-col justify-end transition-all duration-300"
                                style={{ 
                                    width: `${widthPercent}%`,
                                    backgroundColor: phaseColor + (idx === currentIndex ? 'FF' : '33') // Full opacity for current, 20% for others
                                }}
                            >
                                {idx === currentIndex && (
                                    <div className="absolute inset-0 bg-white/10 animate-pulse" />
                                )}
                            </div>
                        );
                    })}

                    {/* Playhead */}
                    <div 
                        className="absolute top-0 bottom-0 w-1.5 bg-white shadow-[0_0_15px_rgba(255,255,255,0.8)] z-20 transition-all duration-1000 linear"
                        style={{ left: `${playheadPos}%` }}
                    />
                </div>

                {/* Annotation Area (Current Phase) - Redesigned as requested */}
                <div className="relative flex items-center justify-center h-24">
                     <div className="flex items-center w-full max-w-xl">
                        {/* Bold Representing Segment */}
                        <div 
                            className="w-1.5 h-16 rounded-full shrink-0 shadow-[0_0_15px_rgba(0,0,0,0.1)]"
                            style={{ backgroundColor: (COLORS as any)[phases[currentIndex]?.type] || '#4F46E5' }}
                        ></div>

                        {/* Dashed Line from MIDPOINT */}
                        <div className="flex-1 h-px border-b-2 border-dashed border-gray-300 dark:border-gray-700 mx-4" />

                        {/* Text Content - Centered relative to line endpoint */}
                        <div className="flex flex-col items-end shrink-0">
                            <div className="text-sm font-bold text-gray-400 dark:text-gray-500 uppercase tracking-[0.2em] mb-1">
                                {phases[currentIndex]?.label}
                            </div>
                            <div className="text-3xl font-mono font-bold text-gray-900 dark:text-white tabular-nums tracking-tighter">
                                {formatTime(phases[currentIndex]?.duration)}
                            </div>
                        </div>
                     </div>
                </div>
            </div>
        </div>
    );
};

const TimeControl = ({ 
  label, 
  value, 
  onChange, 
  max = 1800,
  step = 5,
  disabled = false
}: { 
  label: string; 
  value: number; 
  onChange: (val: number) => void;
  max?: number;
  step?: number;
  disabled?: boolean;
}) => {
  const percentage = Math.min(100, (value / max) * 100);

  return (
    <div className={`w-full group relative transition-all duration-200 p-3 rounded-lg ${disabled ? 'opacity-50 pointer-events-none' : 'hover:bg-gray-50 dark:hover:bg-gray-800/50 focus-within:bg-indigo-50 dark:focus-within:bg-indigo-900/10 focus-within:ring-1 focus-within:ring-indigo-200 dark:focus-within:ring-indigo-800'}`}>
      <div className="flex justify-between items-center mb-2">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 group-focus-within:text-indigo-600 dark:group-focus-within:text-indigo-400 transition-colors">
            {label}
        </label>
        <div className="font-mono text-sm font-bold text-indigo-600 dark:text-indigo-400 bg-white dark:bg-gray-900 px-2 py-0.5 rounded border border-gray-200 dark:border-gray-700 shadow-sm min-w-[3.5rem] text-center">
            {formatTime(value)}
        </div>
      </div>

      <div className="relative h-6 flex items-center">
        <div className="absolute w-full h-2.5 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
             <div 
                className="h-full bg-indigo-500 dark:bg-indigo-400 transition-all duration-75"
                style={{ width: `${percentage}%` }}
             />
        </div>
        <input 
          type="range" 
          min="0" 
          max={max} 
          step={step} 
          value={Math.min(value, max)} 
          onChange={(e) => onChange(Number(e.target.value))}
          disabled={disabled}
          className="absolute w-full h-full opacity-0 cursor-pointer z-10"
        />
        <div 
            className="absolute h-4.5 w-4.5 bg-white border-2 border-indigo-600 rounded-full shadow-lg pointer-events-none transition-all duration-75 group-focus-within:scale-125 group-focus-within:border-indigo-500"
            style={{ left: `calc(${percentage}% - 9px)` }}
        />
      </div>
    </div>
  );
};

