// --- Main Component ---

interface DevTimerProps {
  isOpen: boolean;
  onClose: () => void;
}

export const DevTimer: React.FC<DevTimerProps> = ({ isOpen, onClose }) => {
  const { t } = useLanguage();
  const [mode, setMode] = useState<'setup' | 'running' | 'finished'>('setup');
  const [config, setConfig] = useState<TimerConfig>(DEFAULT_CONFIG);
  const [recipes, setRecipes] = useState<DevRecipe[]>([]);
  const [phases, setPhases] = useState<any[]>([]); 
  const [currentPhaseIndex, setCurrentPhaseIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isPaused, setIsPaused] = useState(true);
  const [agitationState, setAgitationState] = useState<'none' | 'agitate' | 'stand' | 'pre-warn'>('none');
  const audioCtxRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    if (isOpen) { storageService.getRecipes().then(setRecipes); }
  }, [isOpen]);

  const totalProcessTime = useMemo(() => {
    let total = 0;
    if (config.enablePreWet) total += config.preWetTime;
    const singleLoopDevTime = config.developerSteps.reduce((acc, step) => acc + step.duration, 0);
    total += singleLoopDevTime * Math.max(1, config.devLoopCount);
    if (config.enableStopBath) total += config.stopTime;
    total += config.fixTime;
    total += config.washTime;
    return total;
  }, [config]);

  useEffect(() => {
    const buildPhases = () => {
      const list: any[] = [];
      const getAgSettings = (local: any, override?: boolean) => {
         if (config.globalAgitationEnabled && !override) {
             return { initial: config.globalInitialAgitation ?? 30, duration: config.globalAgitationDuration ?? 5, stand: config.globalStandDuration ?? 55 };
         }
         return { initial: local.initial, duration: local.agitate, stand: local.stand };
      };

      if (config.enablePreWet) {
        list.push({ type: 'prewet', label: config.preWetName || t('timer.phase_prewet'), duration: config.preWetTime });
      }

      const loops = Math.max(1, config.devLoopCount);
      for(let i=0; i<loops; i++) {
        config.developerSteps.forEach((step) => {
          let name = step.name || t('timer.phase_develop');
          if (loops > 1) name += ` (${i+1}/${loops})`;
          const agi = getAgSettings({ initial: step.initialAgitation, agitate: step.agitationDuration, stand: step.standDuration }, step.overrideGlobalAgitation);
          list.push({ type: 'develop', label: name, duration: step.duration, initialAgitation: agi.initial, agitationDuration: agi.duration, standDuration: agi.stand });
        });
      }

      if (config.enableStopBath) {
        list.push({ type: 'stop', label: config.stopBathName || t('timer.phase_stop'), duration: config.stopTime });
      }

      const fixAgi = getAgSettings({ initial: config.fixInitialAgitation, agitate: config.fixAgitationDuration, stand: config.fixStandDuration }, config.fixOverrideGlobalAgitation);
      list.push({ type: 'fix', label: config.fixerName || t('timer.phase_fix'), duration: config.fixTime, initialAgitation: fixAgi.initial, agitationDuration: fixAgi.duration, standDuration: fixAgi.stand });
      list.push({ type: 'wash', label: config.washName || t('timer.phase_wash'), duration: config.washTime });
      setPhases(list);
    };
    buildPhases();
  }, [config, t]);

  useEffect(() => {
    let interval: any = null;
    if (mode === 'running' && !isPaused && timeLeft > 0) {
      interval = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (mode === 'running' && !isPaused && timeLeft === 0) {
      handlePhaseComplete();
    }
    return () => { if (interval) clearInterval(interval); };
  }, [mode, isPaused, timeLeft]);

  useEffect(() => {
    if (mode !== 'running' || isPaused) { setAgitationState('none'); return; }
    const currentPhase = phases[currentPhaseIndex];
    if (!currentPhase || (currentPhase.type !== 'develop' && currentPhase.type !== 'fix')) { setAgitationState('none'); return; }
    const initial = currentPhase.initialAgitation || 0;
    const agitateTime = currentPhase.agitationDuration || 0;
    const standTime = currentPhase.standDuration || 0;
    const cycleTime = agitateTime + standTime;
    const elapsed = currentPhase.duration - timeLeft;
    let newState: 'none' | 'agitate' | 'stand' | 'pre-warn' = 'stand';
    if (elapsed < initial) { newState = 'agitate'; } 
    else if (cycleTime > 0) {
        const timeSinceInitial = elapsed - initial;
        const timeInCycle = timeSinceInitial % cycleTime;
        if (timeInCycle < agitateTime) { newState = 'agitate'; } 
        else {
             const timeUntilNextAgitate = cycleTime - timeInCycle;
             if (timeUntilNextAgitate <= 10 && timeUntilNextAgitate > 0 && timeLeft > 10) { newState = 'pre-warn'; } 
             else { newState = 'stand'; }
        }
    } else { newState = 'stand'; }
    if (newState !== agitationState) {
        if (newState === 'agitate') playTone(659, audioCtxRef.current?.currentTime || 0, 0.4); 
        setAgitationState(newState);
    }
  }, [timeLeft, mode, isPaused]);

  const initAudio = () => {
    if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    if (audioCtxRef.current.state === 'suspended') audioCtxRef.current.resume();
  };

  const playTone = (freq: number, startTime: number, duration: number) => {
      if (!audioCtxRef.current) return;
      const osc = audioCtxRef.current.createOscillator();
      const gain = audioCtxRef.current.createGain();
      osc.connect(gain); gain.connect(audioCtxRef.current.destination);
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
      osc.start(startTime); osc.stop(startTime + duration);
  };

  const startTimer = () => {
    initAudio();
    if (mode === 'setup' || mode === 'finished') {
        setMode('running');
        setCurrentPhaseIndex(0);
        setTimeLeft(phases[0]?.duration || 0);
    }
    setIsPaused(false);
  };

  const handlePhaseComplete = () => {
    if (currentPhaseIndex < phases.length - 1) {
        const nextIdx = currentPhaseIndex + 1;
        setCurrentPhaseIndex(nextIdx);
        setTimeLeft(phases[nextIdx].duration);
    } else {
        setMode('finished');
        setIsPaused(true);
    }
  };

  const reset = () => { setMode('setup'); setIsPaused(true); setCurrentPhaseIndex(0); };

  const getTimerBgClass = () => {
      if (agitationState === 'agitate') return 'bg-red-600 text-white';
      if (agitationState === 'pre-warn') return 'bg-orange-500 text-white';
      return 'bg-white dark:bg-gray-900 text-gray-900 dark:text-white';
  };

  if (!isOpen) return null;

  const currentPhase = phases[currentPhaseIndex];
  const nextPhase = phases[currentPhaseIndex + 1];

  return (
    <div className="fixed inset-0 z-50 bg-white dark:bg-gray-900 flex flex-col">
      <div className="flex items-center justify-between px-4 py-3 border-b border-gray-200 dark:border-gray-800 shrink-0">
        <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <Clock className="w-5 h-5" /> {t('timer.title')}
        </h2>
        <button onClick={onClose} className="p-2 text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full">
            <X className="w-6 h-6" />
        </button>
      </div>

      {(mode === 'running' || mode === 'finished') && (
          <AnnotatedTimeline 
            phases={phases} 
            currentIndex={currentPhaseIndex} 
            timeLeft={timeLeft} 
            totalTime={totalProcessTime} 
          />
      )}

      <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
          <div className="flex-1 flex flex-col relative overflow-y-auto">
              {mode === 'setup' ? (
                  <div className="flex-1 p-6 max-w-2xl mx-auto w-full space-y-8">
                      {/* Recipe Title Box */}
                      <div className="bg-gray-50 dark:bg-gray-800 p-4 rounded-xl border border-gray-100 dark:border-gray-700">
                        <h4 className="font-bold mb-3 flex items-center gap-2 text-gray-900 dark:text-white uppercase tracking-wider text-xs">
                             <BookOpen className="w-4 h-4 text-indigo-500"/> {t('timer.section_recipe')}
                        </h4>
                        <div className="flex flex-col sm:flex-row gap-2 items-end">
                             <div className="flex-1 w-full">
                                <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{t('timer.process_name')}</label>
                                <input 
                                    className="w-full rounded-md border-gray-300 dark:border-gray-600 shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white sm:text-sm focus:ring-2 focus:ring-indigo-500"
                                    value={config.processName} 
                                    onChange={e => setConfig({...config, processName: e.target.value})} 
                                    placeholder={t('placeholder.process_name')}
                                />
                             </div>
                        </div>
                      </div>

                      <div className="space-y-6">
                          {/* Pre-wet Section */}
                          <div className="border-t pt-4 dark:border-gray-700">
                               <label className="flex items-center justify-between mb-4 cursor-pointer">
                                  <div className="flex items-center gap-2">
                                      <span className="w-2.5 h-2.5 rounded-full bg-blue-500"></span>
                                      <span className="font-bold text-gray-900 dark:text-white">{t('timer.phase_prewet')}</span>
                                  </div>
                                  <input 
                                    type="checkbox" 
                                    className="w-5 h-5 text-blue-600 rounded-md focus:ring-blue-500"
                                    checked={config.enablePreWet} 
                                    onChange={e => setConfig({...config, enablePreWet: e.target.checked})} 
                                  />
                              </label>
                              {config.enablePreWet && (
                                  <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-xl border border-blue-100 dark:border-blue-800/30">
                                      <ChemicalInputs 
                                        nameLabel={t('timer.prewet_agent')}
                                        nameValue={config.preWetName} onNameChange={v => setConfig({...config, preWetName: v})}
                                        dilutionValue={config.preWetDilution} onDilutionChange={v => setConfig({...config, preWetDilution: v})}
                                        volumeValue={config.preWetVolume} onVolumeChange={v => setConfig({...config, preWetVolume: v})}
                                        placeholder={t('placeholder.prewet_agent')}
                                      />
                                      <TimeControl label={t('timer.duration_label')} value={config.preWetTime} max={300} onChange={val => setConfig({...config, preWetTime: val})} />
                                  </div>
                              )}
                          </div>

                          {/* Developer Section */}
                          <div className="border-t pt-4 dark:border-gray-700">
                               <h4 className="font-bold mb-4 text-gray-900 dark:text-white flex items-center gap-2 uppercase text-sm tracking-widest">
                                  <span className="w-2.5 h-2.5 rounded-full bg-amber-500"></span>
                                  {t('timer.section_dev')}
                               </h4>
                               {config.developerSteps.map((step, idx) => (
                                   <div key={step.id} className="mb-6 p-4 bg-gray-50 dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                                       <ChemicalInputs 
                                            nameLabel={t('timer.dev_liquid_name')}
                                            nameValue={step.name} onNameChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].name = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            dilutionValue={step.dilution} onDilutionChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].dilution = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            volumeValue={step.volume} onVolumeChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].volume = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                       />
                                       <TimeControl label={t('timer.duration_label')} value={step.duration} onChange={val => {
                                            const newSteps = [...config.developerSteps]; newSteps[idx].duration = val; setConfig({...config, developerSteps: newSteps});
                                       }} />

                                       {/* Independent Agitation for Dev Step */}
                                       <AgitationOverride 
                                            enabled={step.overrideGlobalAgitation || false}
                                            onChangeEnable={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].overrideGlobalAgitation = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            initial={step.initialAgitation}
                                            onInitialChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].initialAgitation = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            agitate={step.agitationDuration}
                                            onAgitateChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].agitationDuration = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                            stand={step.standDuration}
                                            onStandChange={v => {
                                                const newSteps = [...config.developerSteps]; newSteps[idx].standDuration = v; setConfig({...config, developerSteps: newSteps});
                                            }}
                                       />
                                   </div>
                               ))}
                          </div>

                          {/* Stop Bath Selection - Integrated in Dev Phase */}
                          <div className="border-t pt-4 dark:border-gray-700">
                              <label className="flex items-center justify-between mb-4 cursor-pointer">
                                  <div className="flex items-center gap-2">
                                      <span className="w-2.5 h-2.5 rounded-full bg-purple-500"></span>
                                      <span className="font-bold text-gray-900 dark:text-white uppercase text-sm tracking-widest">{t('timer.section_stop')}</span>
                                  </div>
                                  <input 
                                    type="checkbox" 
                                    className="w-5 h-5 text-purple-600 rounded-md focus:ring-purple-500"
                                    checked={config.enableStopBath} 
                                    onChange={e => setConfig({...config, enableStopBath: e.target.checked})} 
                                  />
                              </label>
                              {config.enableStopBath && (
                                  <div className="p-4 bg-purple-50 dark:bg-purple-900/10 rounded-xl border border-purple-100 dark:border-purple-800/30">
                                      <ChemicalInputs 
                                        nameLabel={t('timer.stop_agent')}
                                        nameValue={config.stopBathName} onNameChange={v => setConfig({...config, stopBathName: v})}
                                        dilutionValue={config.stopBathDilution} onDilutionChange={v => setConfig({...config, stopBathDilution: v})}
                                        volumeValue={config.stopBathVolume} onVolumeChange={v => setConfig({...config, stopBathVolume: v})}
                                      />
                                      <TimeControl label={t('timer.duration_label')} value={config.stopTime} max={300} onChange={val => setConfig({...config, stopTime: val})} />
                                  </div>
                              )}
                          </div>

                          {/* Fixer Section */}
                          <div className="border-t pt-4 dark:border-gray-700">
                               <h4 className="font-bold mb-4 text-gray-900 dark:text-white flex items-center gap-2 uppercase text-sm tracking-widest">
                                  <span className="w-2.5 h-2.5 rounded-full bg-teal-500"></span>
                                  {t('timer.section_fix')}
                               </h4>
                               <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                                   <ChemicalInputs 
                                        nameLabel={t('timer.fix_liquid_name')}
                                        nameValue={config.fixerName} onNameChange={v => setConfig({...config, fixerName: v})}
                                        dilutionValue={config.fixerDilution} onDilutionChange={v => setConfig({...config, fixerDilution: v})}
                                        volumeValue={config.fixerVolume} onVolumeChange={v => setConfig({...config, fixerVolume: v})}
                                   />
                                   <TimeControl label={t('timer.duration_label')} value={config.fixTime} max={1200} onChange={val => setConfig({...config, fixTime: val})} />

                                   {/* Independent Agitation for Fixer */}
                                   <AgitationOverride 
                                        enabled={config.fixOverrideGlobalAgitation || false}
                                        onChangeEnable={v => setConfig({...config, fixOverrideGlobalAgitation: v})}
                                        initial={config.fixInitialAgitation}
                                        onInitialChange={v => setConfig({...config, fixInitialAgitation: v})}
                                        agitate={config.fixAgitationDuration}
                                        onAgitateChange={v => setConfig({...config, fixAgitationDuration: v})}
                                        stand={config.fixStandDuration}
                                        onStandChange={v => setConfig({...config, fixStandDuration: v})}
                                   />
                               </div>
                          </div>

                           {/* Wash Section */}
                           <div className="border-t pt-4 dark:border-gray-700 pb-12">
                               <h4 className="font-bold mb-4 text-gray-900 dark:text-white flex items-center gap-2 uppercase text-sm tracking-widest">
                                  <span className="w-2.5 h-2.5 rounded-full bg-cyan-500"></span>
                                  {t('timer.section_wash')}
                               </h4>
                               <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm">
                                   <ChemicalInputs 
                                        nameLabel={t('timer.agent_name')}
                                        nameValue={config.washName} onNameChange={v => setConfig({...config, washName: v})}
                                        dilutionValue={config.washDilution} onDilutionChange={v => setConfig({...config, washDilution: v})}
                                        volumeValue={config.washVolume} onVolumeChange={v => setConfig({...config, washVolume: v})}
                                   />
                                   <TimeControl label={t('timer.duration_label')} value={config.washTime} onChange={val => setConfig({...config, washTime: val})} />
                               </div>
                           </div>
                      </div>
                  </div>
              ) : mode === 'finished' ? (
                  <div className="flex-1 flex flex-col items-center justify-center p-8 text-center">
                      <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6">
                          <Check className="w-10 h-10" />
                      </div>
                      <h2 className="text-3xl font-bold mb-2 text-gray-900 dark:text-white">{t('timer.finished_msg')}</h2>
                      <Button size="lg" onClick={reset} className="mt-8">{t('timer.close')}</Button>
                  </div>
              ) : (
                  <div className={`flex-1 flex flex-col items-center justify-center p-8 transition-colors duration-500 ${getTimerBgClass()}`}>
                      <div className="text-center w-full max-w-md">
                          <div className={`text-9xl font-mono font-bold tracking-tighter mb-8 tabular-nums ${agitationState !== 'none' && agitationState !== 'stand' ? 'text-white' : 'text-gray-900 dark:text-white'}`}>
                              {formatTime(timeLeft)}
                          </div>
                          <div className="h-16 flex items-center justify-center">
                             {agitationState === 'agitate' && <div className="flex items-center gap-2 text-3xl font-bold animate-bounce text-white"><Bell className="w-8 h-8 fill-current" /> {t('timer.alert_agitate')}</div>}
                             {agitationState === 'stand' && <div className="flex items-center gap-2 text-xl font-bold text-gray-400"><Coffee className="w-6 h-6" /> {t('timer.alert_stand')}</div>}
                          </div>
                      </div>
                  </div>
              )}

              <div className="p-4 border-t border-gray-200 dark:border-gray-800 bg-gray-50 dark:bg-gray-900 sticky bottom-0">
                  <div className="max-w-md mx-auto flex justify-center gap-4">
                      {mode === 'setup' ? (
                          <Button size="lg" className="w-full h-14 text-lg" onClick={startTimer}>
                              <Play className="w-6 h-6 mr-2" /> {t('timer.start')}
                          </Button>
                      ) : mode === 'running' ? (
                          <>
                            <Button variant="secondary" onClick={reset}><RotateCcw className="w-5 h-5" /></Button>
                            <Button size="lg" className="w-32 h-14" onClick={() => setIsPaused(!isPaused)}>
                                {isPaused ? <Play className="w-6 h-6" /> : <Pause className="w-6 h-6" />}
                            </Button>
                            <Button variant="secondary" onClick={handlePhaseComplete}><SkipForward className="w-5 h-5" /></Button>
                          </>
                      ) : null}
                  </div>
              </div>
          </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Camera, Beaker, Upload, Image as ImageIcon, BookOpen } from 'lucide-react';
import { FilmRecord, FilmFormat, DevMethod, FILM_FORMATS, DEV_METHODS, DevRecipe } from '../types';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { useLanguage } from '../contexts/LanguageContext';
import { storageService } from '../services/storageService';

interface RecordEditorProps {
  initialData?: FilmRecord | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (record: FilmRecord) => Promise<void>;
}

const emptyRecord: Omit<FilmRecord, 'id' | 'createdAt' | 'updatedAt'> = {
  date: Date.now(),
  filmModel: '',
  format: '135',
  aperture: '',
  shutterSpeed: '',
  flashPower: '',
  location: '',
  locationImage: null,
  shootingNotes: '',
  devMethod: 'Hand',
  devProcess: 'BW',
  developerModel: '',
  fixerModel: '',
  devDilution: '',
  fixDilution: '',
  isPreWet: false,
  devTime: '',
  fixTime: '',
  devNotes: '',
  filmImage: null,
};

// Helper to format timestamp for datetime-local input (YYYY-MM-DDThh:mm)
const formatDateForInput = (timestamp: number) => {
  const date = new Date(timestamp);
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

// Helper to format Seconds to M:SS
const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
};

export const RecordEditor: React.FC<RecordEditorProps> = ({ initialData, isOpen, onClose, onSave }) => {
  const { t } = useLanguage();
  const [activeTab, setActiveTab] = useState<'shooting' | 'developing'>('shooting');
  const [formData, setFormData] = useState<any>(emptyRecord);
  const [isSaving, setIsSaving] = useState(false);
  const [recipes, setRecipes] = useState<DevRecipe[]>([]);

  useEffect(() => {
    if (isOpen) {
      const initialDate = initialData 
        ? (initialData.date || initialData.createdAt || Date.now()) 
        : Date.now();

      setFormData({
        ...(initialData || emptyRecord),
        date: initialDate
      });
      setActiveTab('shooting');

      storageService.getRecipes().then(setRecipes);
    }
  }, [isOpen, initialData]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'locationImage' | 'filmImage') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData((prev: any) => ({ ...prev, [field]: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const dateString = e.target.value;
    if (dateString) {
      const timestamp = new Date(dateString).getTime();
      setFormData({ ...formData, date: timestamp });
    }
  };

  const handleRecipeSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
      const recipeId = e.target.value;
      if(!recipeId) return;
      const recipe = recipes.find(r => r.id === recipeId);
      if(recipe) {
          const totalDevSeconds = recipe.config.developerSteps.reduce((acc, step) => acc + step.duration, 0) * recipe.config.devLoopCount;

          setFormData({
              ...formData,
              devMethod: recipe.config.devMethod,
              developerModel: recipe.config.developerSteps[0]?.name || recipe.config.developerModel,
              devDilution: recipe.config.developerSteps[0]?.dilution || '',
              devTime: formatTime(totalDevSeconds),
              fixTime: formatTime(recipe.config.fixTime),
              isPreWet: recipe.config.enablePreWet,
              devNotes: recipe.notes || formData.devNotes
          });
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const recordToSave: FilmRecord = {
        ...formData,
        id: initialData?.id || Date.now().toString(),
        createdAt: initialData?.createdAt || Date.now(),
        updatedAt: Date.now(),
      };
      await onSave(recordToSave);
      onClose();
    } catch (error) {
      console.error("Failed to save", error);
      alert(t('editor.save_fail'));
    } finally {
      setIsSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto">
      <div className="flex items-center justify-center min-h-screen px-4 pt-4 pb-20 text-center sm:block sm:p-0">
        <div className="fixed inset-0 transition-opacity bg-gray-500 bg-opacity-75" onClick={onClose} />

        <div className="inline-block w-full max-w-2xl my-8 overflow-hidden text-left align-middle transition-all transform bg-white dark:bg-gray-800 shadow-xl rounded-2xl">
          <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-gray-700 bg-gray-50 dark:bg-gray-900">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white">
              {initialData ? t('editor.edit_title') : t('editor.new_title')}
            </h3>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-500 dark:hover:text-gray-300">
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex border-b border-gray-200 dark:border-gray-700">
            <button
              onClick={() => setActiveTab('shooting')}
              className={`flex-1 py-3 text-sm font-medium text-center border-b-2 transition-colors flex items-center justify-center gap-2 ${
                activeTab === 'shooting'
                  ? 'border-indigo-500 text-indigo-600 dark:text-indigo-400 bg-indigo-50/50 dark:bg-indigo-900/20'
                  : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'
              }`}
            >
              <Camera className="w-4 h-4" /> {t('editor.tab_shooting')}
            </button>
            <button
              onClick={() => setActiveTab('developing')}
              className={`flex-1 py-3 text-sm font-medium text-center border-b-2 transition-colors flex items-center justify-center gap-2 ${
                activeTab === 'developing'
                  ? 'border-indigo-500 text-indigo-600 dark:text-indigo-400 bg-indigo-50/50 dark:bg-indigo-900/20'
                  : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'
              }`}
            >
              <Beaker className="w-4 h-4" /> {t('editor.tab_developing')}
            </button>
          </div>

          <form onSubmit={handleSubmit} className="px-6 py-6 max-h-[70vh] overflow-y-auto">
            {activeTab === 'shooting' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <Input
                  label={t('field.date')}
                  type="datetime-local"
                  value={formatDateForInput(formData.date)}
                  onChange={handleDateChange}
                  required
                  className="md:col-span-2 font-mono"
                />

                <Input
                  label={t('field.filmModel')}
                  placeholder={t('placeholder.filmModel')}
                  value={formData.filmModel}
                  onChange={(e) => setFormData({ ...formData, filmModel: e.target.value })}
                  required
                  className="md:col-span-2"
                />

                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('field.format')}</label>
                  <select
                    className="w-full rounded-md border-gray-300 dark:border-gray-600 border shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm"
                    value={formData.format}
                    onChange={(e) => setFormData({ ...formData, format: e.target.value as FilmFormat })}
                  >
                    {FILM_FORMATS.map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                </div>

                <Input
                  label={t('field.location')}
                  placeholder={t('placeholder.location')}
                  value={formData.location}
                  onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                />

                <Input
                  label={t('field.aperture')}
                  placeholder={t('placeholder.aperture')}
                  value={formData.aperture}
                  onChange={(e) => setFormData({ ...formData, aperture: e.target.value })}
                />

                <Input
                  label={t('field.shutterSpeed')}
                  placeholder={t('placeholder.shutterSpeed')}
                  value={formData.shutterSpeed}
                  onChange={(e) => setFormData({ ...formData, shutterSpeed: e.target.value })}
                />

                <Input
                  label={t('field.flashPower')}
                  placeholder={t('placeholder.flashPower')}
                  value={formData.flashPower}
                  onChange={(e) => setFormData({ ...formData, flashPower: e.target.value })}
                />

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('editor.preview_location')}</label>
                  <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 dark:border-gray-600 border-dashed rounded-md hover:border-indigo-400 dark:hover:border-indigo-500 transition-colors">
                    <div className="space-y-1 text-center">
                      {formData.locationImage ? (
                        <div className="relative">
                            <img src={formData.locationImage} alt="Preview" className="mx-auto h-32 object-contain" />
                            <button 
                                type="button"
                                onClick={() => setFormData({...formData, locationImage: null})}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 hover:bg-red-600"
                            >
                                <X className="w-3 h-3" />
                            </button>
                        </div>
                      ) : (
                        <>
                          <ImageIcon className="mx-auto h-12 w-12 text-gray-400 dark:text-gray-500" />
                          <div className="flex text-sm text-gray-600 dark:text-gray-400 justify-center">
                            <label className="relative cursor-pointer bg-white dark:bg-gray-700 rounded-md font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-500 dark:hover:text-indigo-300 focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-indigo-500">
                              <span className="px-1">{t('editor.upload')}</span>
                              <input type="file" className="sr-only" accept="image/*" onChange={(e) => handleImageUpload(e, 'locationImage')} />
                            </label>
                          </div>
                          <p className="text-xs text-gray-500 dark:text-gray-400">{t('editor.upload_hint')}</p>
                        </>
                      )}
                    </div>
                  </div>
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('field.shootingNotes')}</label>
                  <textarea
                    rows={3}
                    className="w-full rounded-md border-gray-300 dark:border-gray-600 border shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm"
                    value={formData.shootingNotes}
                    onChange={(e) => setFormData({ ...formData, shootingNotes: e.target.value })}
                  />
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">

                <div className="md:col-span-2 bg-indigo-50 dark:bg-indigo-900/10 p-3 rounded-lg border border-indigo-100 dark:border-indigo-800/30">
                    <label className="block text-sm font-medium text-indigo-700 dark:text-indigo-300 mb-1 flex items-center gap-2">
                        <BookOpen className="w-4 h-4" /> {t('editor.load_recipe')}
                    </label>
                    <select
                        className="w-full rounded-md border-gray-300 dark:border-gray-600 border shadow-sm px-3 py-2 bg-white dark:bg-gray-800 text-gray-900 dark:text-white focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm"
                        onChange={handleRecipeSelect}
                        defaultValue=""
                    >
                        <option value="" disabled>{t('editor.recipe_placeholder')}</option>
                        {recipes.map(recipe => (
                            <option key={recipe.id} value={recipe.id}>{recipe.name}</option>
                        ))}
                    </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('field.devMethod')}</label>
                  <select
                    className="w-full rounded-md border-gray-300 dark:border-gray-600 border shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm"
                    value={formData.devMethod}
                    onChange={(e) => setFormData({ ...formData, devMethod: e.target.value as DevMethod })}
                  >
                    {DEV_METHODS.map(m => <option key={m} value={m}>{t(`enum.${m}`)}</option>)}
                  </select>
                </div>

                <Input
                  label={t('field.devProcess')}
                  placeholder={t('placeholder.devProcess')}
                  value={formData.devProcess}
                  onChange={(e) => setFormData({ ...formData, devProcess: e.target.value })}
                />

                <Input
                  label={t('field.developerModel')}
                  placeholder={t('placeholder.developerModel')}
                  value={formData.developerModel}
                  onChange={(e) => setFormData({ ...formData, developerModel: e.target.value })}
                />

                <Input
                  label={t('field.devDilution')}
                  placeholder={t('placeholder.devDilution')}
                  value={formData.devDilution}
                  onChange={(e) => setFormData({ ...formData, devDilution: e.target.value })}
                />

                 <Input
                  label={t('field.devTime')}
                  placeholder={t('placeholder.devTime')}
                  value={formData.devTime}
                  onChange={(e) => setFormData({ ...formData, devTime: e.target.value })}
                />

                <div className="flex items-center mt-6">
                    <input
                        id="prewet"
                        type="checkbox"
                        checked={formData.isPreWet}
                        onChange={(e) => setFormData({ ...formData, isPreWet: e.target.checked })}
                        className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                    />
                    <label htmlFor="prewet" className="ml-2 block text-sm text-gray-900 dark:text-gray-300">
                        {t('editor.prewet')}
                    </label>
                </div>

                <Input
                  label={t('field.fixerModel')}
                  placeholder={t('placeholder.fixerModel')}
                  value={formData.fixerModel}
                  onChange={(e) => setFormData({ ...formData, fixerModel: e.target.value })}
                />

                <Input
                  label={t('field.fixDilution')}
                  placeholder={t('placeholder.fixDilution')}
                  value={formData.fixDilution}
                  onChange={(e) => setFormData({ ...formData, fixDilution: e.target.value })}
                />

                <Input
                  label={t('field.fixTime')}
                  placeholder={t('placeholder.fixTime')}
                  value={formData.fixTime}
                  onChange={(e) => setFormData({ ...formData, fixTime: e.target.value })}
                />

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('editor.preview_film')}</label>
                  <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 dark:border-gray-600 border-dashed rounded-md hover:border-indigo-400 dark:hover:border-indigo-500 transition-colors">
                     <div className="space-y-1 text-center">
                      {formData.filmImage ? (
                        <div className="relative">
                            <img src={formData.filmImage} alt="Preview" className="mx-auto h-32 object-contain" />
                            <button 
                                type="button"
                                onClick={() => setFormData({...formData, filmImage: null})}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 hover:bg-red-600"
                            >
                                <X className="w-3 h-3" />
                            </button>
                        </div>
                      ) : (
                        <>
                          <ImageIcon className="mx-auto h-12 w-12 text-gray-400 dark:text-gray-500" />
                          <div className="flex text-sm text-gray-600 dark:text-gray-400 justify-center">
                            <label className="relative cursor-pointer bg-white dark:bg-gray-700 rounded-md font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-500 dark:hover:text-indigo-300 focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-indigo-500">
                              <span className="px-1">{t('editor.upload')}</span>
                              <input type="file" className="sr-only" accept="image/*" onChange={(e) => handleImageUpload(e, 'filmImage')} />
                            </label>
                          </div>
                          <p className="text-xs text-gray-500 dark:text-gray-400">{t('editor.upload_hint_film')}</p>
                        </>
                      )}
                    </div>
                  </div>
                </div>

                 <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">{t('field.devNotes')}</label>
                  <textarea
                    rows={3}
                    className="w-full rounded-md border-gray-300 dark:border-gray-600 border shadow-sm px-3 py-2 bg-white dark:bg-gray-700 text-gray-900 dark:text-white focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm"
                    value={formData.shootingNotes}
                    onChange={(e) => setFormData({ ...formData, devNotes: e.target.value })}
                  />
                </div>
              </div>
            )}

            <div className="mt-8 flex justify-end gap-3 pt-4 border-t border-gray-100 dark:border-gray-700">
              <Button type="button" variant="secondary" onClick={onClose}>
                {t('editor.cancel')}
              </Button>
              <Button type="submit" variant="primary" isLoading={isSaving}>
                {initialData ? t('editor.update') : t('editor.save_upload')}
              </Button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};
